import*as http from"http";import*as https from"https";export async function toBuffer(t){let r=0;const n=[];for await(const e of t)r+=e.length,n.push(e);return Buffer.concat(n,r)}export async function json(t){const r=(await toBuffer(t)).toString("utf8");try{return JSON.parse(r)}catch(t){const n=t;throw n.message+=` (input: ${r})`,n}}export function req(t,r={}){const n=(("string"==typeof t?t:t.href).startsWith("https:")?https:http).request(t,r),e=new Promise((t,r)=>{n.once("response",t).once("error",r).end()});return n.then=e.then.bind(e),n}